// Unit 15 — Comparaciones
// Comparatives & Superlatives

export default {n:15,lang:"es",srcLang:"en",track:"v2",title:"Comparaciones",sub:"Comparatives & Superlatives",icon:"⚖️",level:"A2.4",color:"#7B5EE8",lessons:[
  {id:"esp15l1",title:"Más...que",icon:"📏",xp:20,board:true,steps:[
        {type:"intro",title:"Más...que",desc:"Learn to compare two things using mas...que (more...than). This is the most common comparison structure in Spanish.",goals:["Use mas...que with adjectives","Compare people and objects","Build natural comparison sentences"]},
        {type:"teach",trg:"más...que",src:"more...than",pos:"noun",gender:null,phonetic:"mahs...keh",note:"The basic comparison formula: subject + es + mas + adjective + que + noun.",example:"A: ¿Quién es más alto, Pedro o Luis?\nB: Pedro es más alto que Luis.\nA: ¿Y quién es más rápido?\nB: Luis es más rápido que Pedro.",exampleSrc:"A: Who is taller, Pedro or Luis?\nB: Pedro is taller than Luis.\nA: And who is faster?\nB: Luis is faster than Pedro.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"alto",src:"tall",pos:"adj",gender:null,phonetic:"AHL-toh",note:"alto/alta/altos/altas. Gender and number agree with the subject.",example:"A: ¿Es alto tu hermano?\nB: Si, es muy alto. Es más alto que yo.\nA: ¿Cuánto mide?\nB: Mide un metro noventa.",exampleSrc:"A: Is your brother tall?\nB: Yes, he is very tall. He is taller than me.\nA: How tall is he?\nB: He is one meter ninety.",funFact:"Spanish adjectives agree in gender and number. Most change -o/-a for gender and add -s for plural."},
        {type:"teach",trg:"caro",src:"expensive",pos:"adj",gender:null,phonetic:"KAH-roh",note:"caro/cara/caros/caras. Used for prices and costs.",example:"A: ¿Es caro este restaurante?\nB: Si, es más caro que el restaurante de la esquina.\nA: Pero la comida es buena, ¿no?\nB: Si, mucho más rica.",exampleSrc:"A: Is this restaurant expensive?\nB: Yes, it is more expensive than the restaurant on the corner.\nA: But the food is good, right?\nB: Yes, much more delicious.",funFact:"Spanish adjectives agree in gender and number. Most change -o/-a for gender and add -s for plural."},
        {type:"teach",trg:"rápido",src:"fast",pos:"verb",gender:null,phonetic:"RRAH-pee-doh",note:"rapido/rapida. Also used as an adverb: habla rapido (speaks fast).",example:"A: ¿Es más rápido el tren o el autobus?\nB: El tren es más rápido que el autobus.\nA: ¿Y más barato?\nB: No, el autobus es más barato.",exampleSrc:"A: Is the train or the bus faster?\nB: The train is faster than the bus.\nA: And cheaper?\nB: No, the bus is cheaper.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"tip",title:"The mas...que formula",text:"To compare with adjectives:\n\nSubject + ser + mas + adjective + que + noun\n\nEl coche es mas caro que la bicicleta.\nMaria es mas alta que Pedro.\n\nThe adjective agrees with the SUBJECT, not with que."},
        {type:"teach",trg:"grande",src:"big, large",pos:"noun",gender:"m",phonetic:"GRAHN-deh",note:"grande/grandes. Same form for masculine and feminine.",example:"A: ¿Tu casa es grande?\nB: Si, es más grande que mi apartamento anterior.\nA: ¿Tiene jardin?\nB: Si, un jardin bastante grande.",exampleSrc:"A: Is your house big?\nB: Yes, it is bigger than my previous apartment.\nA: Does it have a garden?\nB: Yes, a fairly big garden.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"dificil",src:"difficult",pos:"adj",gender:null,phonetic:"dee-FEE-seel",note:"dificil/dificiles. Same form for masculine and feminine. Plural adds -es.",example:"A: ¿El examen es dificil?\nB: Si, es más dificil que el examen del mes pasado.\nA: ¿Estudiaste mucho?\nB: Si, estudie toda la semana.",exampleSrc:"A: Is the exam difficult?\nB: Yes, it is harder than last month's exam.\nA: Did you study a lot?\nB: Yes, I studied all week.",funFact:"Cognate with English 'difficult'. Spanish and English share many Latin-derived words."},
        {type:"mc",q:"Choose the correct comparison: El verano es ___ el invierno. (hotter than)",opts:["más caliente que","más caliente de","caliente más que","más que caliente"],ans:"más caliente que",hint:"The formula is mas + adjective + ___."},
        {type:"fb",opts:["alta","alto","altas","altos"],hint:"Your sister is feminine singular, so the adjective must match.",s:"Mi hermana es más {1} que yo.",a:["alta"]},
        {type:"mc",q:"María es más inteligente ___ Juan.",opts:["de","que","como","por"],ans:"que",hint:"After mas + adjective, we use a specific comparison word."},
        {type:"fb",opts:["rápido","rápida","rápidos","lento"],hint:"The airplane is masculine singular. Which adjective form matches?",s:"El avion es más {1} que el coche.",a:["rápido"]},
        {type:"match",pairs:[{trg:"más caro que",src:"more expensive than"},{trg:"más alto que",src:"taller than"},{trg:"más grande que",src:"bigger than"},{trg:"más dificil que",src:"harder than"}]},
        {type:"mc",q:"La pizza es más ___ que la ensalada.",opts:["ricos","rico","rica","ricas"],ans:"rica",hint:"La pizza is feminine singular. The adjective must agree."},
        {type:"fb",opts:["interesante","interesantes","interesar","interesada"],hint:"Which word means interesting and agrees with el libro?",s:"Este libro es más {1} que ese.",a:["interesante"]},
        {type:"drag_fill",hint:"Coffee is stronger than tea. Use the comparison formula.",s:"El cafe es {1} {2} {3} el te.",blanks:{"1":"más","2":"fuerte","3":"que"},pool:["más","fuerte","que","como","menos"]},
        {type:"mc",q:"A: ¿Quién es más alto? B: Pedro es más alto ___ Luis.",opts:["con","de","como","que"],ans:"que",hint:"We compare Pedro to Luis using the standard comparison word."},
        {type:"fb",opts:["ruidosa","ruidoso","ruidosos","tranquila"],hint:"La ciudad is feminine. Which adjective means noisy and matches?",s:"La ciudad es más {1} que el pueblo.",a:["ruidosa"]},
        {type:"mc",q:"What does 'Este restaurante es más barato que ese' mean?",opts:["This restaurant is cheaper than that one","This restaurant is more expensive than that one","This restaurant is as cheap as that one","This restaurant is the cheapest"],ans:"This restaurant is cheaper than that one",hint:"Barato means cheap. Mas...que means more...than."}
  ]},
  {id:"esp15l2",title:"Menos...que & Tan...como",icon:"⚖️",xp:20,board:true,steps:[
        {type:"intro",title:"Menos...que & Tan...como",desc:"Learn two more comparison structures: menos...que (less...than) and tan...como (as...as). Together with mas...que, these cover all basic comparisons.",goals:["Use menos...que for less comparisons","Use tan...como for equal comparisons","Choose the right structure for each context"]},
        {type:"teach",trg:"menos...que",src:"less...than",pos:"adj",gender:null,phonetic:"MEH-nohs...keh",note:"Same structure as mas...que but with menos. Subject + ser + menos + adjective + que.",example:"A: ¿Este hotel es caro?\nB: No, es menos caro que el hotel del centro.\nA: ¿Y es bonito?\nB: Es menos bonito, pero es comodo.",exampleSrc:"A: Is this hotel expensive?\nB: No, it is less expensive than the hotel in the center.\nA: And is it nice?\nB: It is less nice, but it is comfortable.",funFact:"Spanish adjectives agree in gender and number. Most change -o/-a for gender and add -s for plural."},
        {type:"teach",trg:"tan...como",src:"as...as",pos:"noun",gender:null,phonetic:"tahn...KOH-moh",note:"For equal comparisons. Subject + ser + tan + adjective + como + noun.",example:"A: ¿Tu coche es rápido?\nB: Si, es tan rápido como el tuyo.\nA: No lo creo.\nB: ¡Es verdad! Los dos van a la misma velocidad.",exampleSrc:"A: Is your car fast?\nB: Yes, it is as fast as yours.\nA: I don't believe it.\nB: It's true! They both go at the same speed.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"bonito",src:"pretty, beautiful",pos:"noun",gender:null,phonetic:"boh-NEE-toh",note:"bonito/bonita/bonitos/bonitas. Common in everyday speech.",example:"A: ¿Qué ciudad es más bonita?\nB: Madrid es tan bonita como Barcelona.\nA: ¿De verdad? Yo creo que Barcelona es más bonita.\nB: Las dos son muy bonitas.",exampleSrc:"A: Which city is prettier?\nB: Madrid is as pretty as Barcelona.\nA: Really? I think Barcelona is prettier.\nB: Both are very pretty.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"comodo",src:"comfortable",pos:"noun",gender:null,phonetic:"KOH-moh-doh",note:"comodo/comoda. Used for furniture, shoes, clothing, situations.",example:"A: ¿Es comodo tu sofa nuevo?\nB: Si, es tan comodo como el viejo.\nA: Entonces, ¿por que compraste uno nuevo?\nB: Porque el viejo era menos bonito.",exampleSrc:"A: Is your new sofa comfortable?\nB: Yes, it is as comfortable as the old one.\nA: Then why did you buy a new one?\nB: Because the old one was less pretty.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"tip",title:"Three comparison structures",text:"1. mas...que = more...than\n  El gato es mas rapido que la tortuga.\n\n2. menos...que = less...than\n  La tortuga es menos rapida que el gato.\n\n3. tan...como = as...as\n  Mi gato es tan grande como el tuyo.\n\nAll three use ser or estar + adjective."},
        {type:"teach",trg:"facil",src:"easy",pos:"adj",gender:null,phonetic:"FAH-seel",note:"facil/faciles. The opposite of dificil.",example:"A: ¿Es facil este ejercicio?\nB: Si, es menos dificil que el anterior.\nA: ¿Tan facil como el primero?\nB: No, no es tan facil como el primero.",exampleSrc:"A: Is this exercise easy?\nB: Yes, it is less difficult than the previous one.\nA: As easy as the first one?\nB: No, it is not as easy as the first one.",funFact:"Spanish adjectives agree in gender and number. Most change -o/-a for gender and add -s for plural."},
        {type:"mc",q:"El gato es ___ grande como el perro.",opts:["tan","más","menos","tanto"],ans:"tan",hint:"For equal comparisons with adjectives, we use a specific word before the adjective."},
        {type:"fb",opts:["dificil","facil","dificiles","bueno"],hint:"The exam is LESS something than the previous one. The sentence says it is easier.",s:"Este examen es menos {1} que el anterior.",a:["dificil"]},
        {type:"mc",q:"What does 'Mi casa es tan grande como la tuya' mean?",opts:["My house is bigger than yours","My house is as big as yours","My house is less big than yours","My house is the biggest"],ans:"My house is as big as yours",hint:"Tan...como expresses equality between two things."},
        {type:"fb",opts:["menos","más","tan","tanto"],hint:"The movie is LESS interesting than the book.",s:"La pelicula es {1} interesante que el libro.",a:["menos"]},
        {type:"match",pairs:[{trg:"tan alto como",src:"as tall as"},{trg:"menos caro que",src:"less expensive than"},{trg:"más rapido que",src:"faster than"},{trg:"tan bonito como",src:"as pretty as"}]},
        {type:"drag_fill",hint:"This coffee is AS good AS yesterday's coffee. Equal comparison.",s:"Este cafe es {1} {2} {3} el cafe de ayer.",blanks:{"1":"tan","2":"bueno","3":"como"},pool:["tan","bueno","como","más","que"]},
        {type:"mc",q:"La bicicleta es ___ rápida ___ el coche.",opts:["tan...que","menos...como","menos...que","más...como"],ans:"menos...que",hint:"Less...than uses ___, not como."},
        {type:"fb",opts:["alto","alta","altos","altas"],hint:"Mi hermano is masculine singular. The adjective must match.",s:"Mi hermano es tan {1} como mi padre.",a:["alto"]},
        {type:"mc",q:"Choose the EQUAL comparison: Mi gato es ___ el tuyo.",opts:["el más grande de","más grande que","menos grande que","tan grande como"],ans:"tan grande como",hint:"We need as big as, which uses ___...___."},
        {type:"drag_fill",hint:"The salad is LESS expensive THAN the soup.",s:"La ensalada es {1} {2} {3} la sopa.",blanks:{"1":"menos","2":"cara","3":"que"},pool:["menos","cara","que","tan","como"]},
        {type:"mc",q:"A: ¿Tu trabajo es dificil? B: No, es ___ dificil ___ tu trabajo.",opts:["menos...que","menos...como","tan...que","más...de"],ans:"menos...que",hint:"Less difficult than. Remember which word follows ___ + adjective."}
  ]},
  {id:"esp15l3",title:"Mejor, Peor, Mayor, Menor",icon:"⭐",xp:20,board:true,steps:[
        {type:"intro",title:"Irregular Comparatives",desc:"Some adjectives have special comparative forms. Mejor (better), peor (worse), mayor (older/bigger), and menor (younger/smaller) replace mas bueno, mas malo, etc.",goals:["Use mejor and peor correctly","Use mayor and menor for age","Know when NOT to use mas with these words"]},
        {type:"teach",trg:"mejor",src:"better",pos:"noun",gender:null,phonetic:"meh-HOHR",note:"Irregular comparative of bueno. NEVER say mas bueno. Always mejor.",example:"A: ¿Qué restaurante es mejor?\nB: El restaurante italiano es mejor que el chino.\nA: ¿Por que?\nB: Porque la comida es más fresca.",exampleSrc:"A: Which restaurant is better?\nB: The Italian restaurant is better than the Chinese one.\nA: Why?\nB: Because the food is fresher.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"peor",src:"worse",pos:"noun",gender:null,phonetic:"peh-OHR",note:"Irregular comparative of malo. NEVER say mas malo. Always peor.",example:"A: ¿Como fue el examen?\nB: Fue peor que el ultimo examen.\nA: ¿Tan malo?\nB: Si, mucho peor. No estudie suficiente.",exampleSrc:"A: How was the exam?\nB: It was worse than the last exam.\nA: That bad?\nB: Yes, much worse. I didn't study enough.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"mayor",src:"older (for people) / bigger",pos:"noun",gender:null,phonetic:"mah-YOHR",note:"For age: mayor = older. Do not say mas viejo for people (it is rude).",example:"A: ¿Quién es mayor, tu o tu hermana?\nB: Yo soy mayor. Tengo tres anos más.\nA: ¿Y tu hermano?\nB: Mi hermano es el mayor de todos.",exampleSrc:"A: Who is older, you or your sister?\nB: I am older. I am three years older.\nA: And your brother?\nB: My brother is the oldest of all.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"menor",src:"younger (for people) / smaller",pos:"noun",gender:null,phonetic:"meh-NOHR",note:"For age: menor = younger. The polite way to compare ages.",example:"A: ¿Tu primo es menor que tu?\nB: Si, es dos anos menor.\nA: ¿Y tu prima?\nB: Ella es la menor de la familia.",exampleSrc:"A: Is your cousin younger than you?\nB: Yes, he is two years younger.\nA: And your female cousin?\nB: She is the youngest in the family.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"tip",title:"Irregular comparatives: never use mas",text:"These four REPLACE mas + adjective:\n\nbueno (good) = mejor (better)\nmalo (bad) = peor (worse)\ngrande (big/old) = mayor (older)\npequeno (small/young) = menor (younger)\n\nNEVER say: mas bueno, mas malo\nFor size (not age): mas grande, mas pequeno are OK."},
        {type:"mc",q:"Este cafe es ___ que el cafe de la otra tienda.",opts:["mejor","más bueno","más mejor","bueno más"],ans:"mejor",hint:"Good/better has an irregular form. We never use mas with it."},
        {type:"fb",opts:["peor","más malo","malo","mejor"],hint:"The weather today is worse. Use the irregular form, not mas malo.",s:"El tiempo hoy es {1} que ayer.",a:["peor"]},
        {type:"mc",q:"Mi abuelo es ___ que mi padre.",opts:["más viejo","mayor","más mayor","viejo"],ans:"mayor",hint:"For comparing ages of people, we use the polite irregular form."},
        {type:"fb",opts:["menor","más joven","pequeña","mayor"],hint:"Ana is younger. Use the irregular comparative for age.",s:"Ana es {1} que su hermano. Tiene 15 anos y el tiene 18.",a:["menor"]},
        {type:"match",pairs:[{trg:"mejor",src:"better"},{trg:"peor",src:"worse"},{trg:"mayor",src:"older"},{trg:"menor",src:"younger"}]},
        {type:"mc",q:"Which sentence is INCORRECT?",opts:["Mi hermana es menor que yo","La sopa es mejor que la ensalada","La sopa es más buena que la ensalada","El tiempo es peor que ayer"],ans:"La sopa es más buena que la ensalada",hint:"One of these uses mas + an adjective that has an irregular comparative form."},
        {type:"drag_fill",hint:"My grade is worse than yours. Use the irregular form.",s:"Mi nota es {1} {2} la tuya.",blanks:{"1":"peor","2":"que"},pool:["peor","que","más","malo","como"]},
        {type:"fb",opts:["mayor","más viejo","más grande","viejo"],hint:"Who is older? Use the polite irregular form for age.",s:"¿Quién es {1}, Luis o Carmen?",a:["mayor"]},
        {type:"mc",q:"A: ¿Este hotel es bueno? B: Si, es ___ que el hotel del ano pasado.",opts:["el mejor","más bueno","bueno","mejor"],ans:"mejor",hint:"Better than uses the irregular comparative, never mas bueno."},
        {type:"mc",q:"What does 'Mi hermano menor tiene veinte anos' mean?",opts:["My younger brother is twenty years old","My smaller brother is twenty years old","My worse brother is twenty years old","My better brother is twenty years old"],ans:"My younger brother is twenty years old",hint:"Menor when referring to people means ___, not smaller."},
        {type:"fb",opts:["peor","mejor","más mala","menos buena"],hint:"The movie was worse. Use the single-word irregular form.",s:"Esta pelicula es {1} que la otra. No me gusto nada.",a:["peor"]},
        {type:"drag_fill",hint:"Carlos is older than Ana but younger than Luis.",s:"Carlos es {1} que Ana pero {2} que Luis.",blanks:{"1":"mayor","2":"menor"},pool:["mayor","menor","más","que","viejo"]}
  ]},
  {id:"esp15l4",title:"El más...de",icon:"🏆",xp:20,board:true,steps:[
        {type:"intro",title:"Superlatives",desc:"Learn to say the most, the best, the tallest, etc. Spanish superlatives use el/la mas + adjective + de.",goals:["Form superlatives with el/la mas","Use irregular superlatives (el mejor, el peor)","Express the most/least within a group"]},
        {type:"teach",trg:"el más...de",src:"the most...in/of",pos:"noun",gender:"m",phonetic:"el mahs...deh",note:"el/la + mas + adjective + de. Use el for masculine, la for feminine.",example:"A: ¿Quién es el más alto de la clase?\nB: Pedro es el más alto de todos.\nA: ¿Y la más alta?\nB: Maria es la más alta de las chicas.",exampleSrc:"A: Who is the tallest in the class?\nB: Pedro is the tallest of all.\nA: And the tallest girl?\nB: Maria is the tallest of the girls.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el mejor...de",src:"the best...in/of",pos:"noun",gender:"m",phonetic:"el meh-HOHR...deh",note:"Irregular superlative. el mejor = the best, la mejor = the best (feminine).",example:"A: ¿Cuál es el mejor restaurante de la ciudad?\nB: El restaurante La Casa es el mejor de todos.\nA: ¿Y el peor?\nB: No quiero decir nombres.",exampleSrc:"A: Which is the best restaurant in the city?\nB: The restaurant La Casa is the best of all.\nA: And the worst?\nB: I don't want to name names.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el peor",src:"the worst",pos:"noun",gender:"m",phonetic:"el peh-OHR",note:"el peor/la peor. Irregular superlative of malo.",example:"A: ¿Fue un buen dia?\nB: No, fue el peor dia de la semana.\nA: ¿Que paso?\nB: Perdi el autobus y llegue tarde al trabajo.",exampleSrc:"A: Was it a good day?\nB: No, it was the worst day of the week.\nA: What happened?\nB: I missed the bus and arrived late to work.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"tip",title:"Forming superlatives",text:"Regular: el/la + mas + adjective + de\n  Maria es la mas alta de la clase.\n  Este es el restaurante mas caro de Madrid.\n\nIrregular:\n  el/la mejor de (the best of)\n  el/la peor de (the worst of)\n  el/la mayor de (the oldest of)\n  el/la menor de (the youngest of)\n\nNote: de = in/of (not en)."},
        {type:"teach",trg:"inteligente",src:"intelligent, smart",pos:"noun",gender:"m",phonetic:"een-teh-lee-HEHN-teh",note:"inteligente/inteligentes. Same form for masculine and feminine.",example:"A: ¿Quién es el más inteligente de tu familia?\nB: Mi hermana es la más inteligente de todos.\nA: ¿Que estudia?\nB: Estudia medicina en la universidad.",exampleSrc:"A: Who is the most intelligent in your family?\nB: My sister is the most intelligent of all.\nA: What does she study?\nB: She studies medicine at the university.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"mc",q:"Pedro es el estudiante más ___ de la clase.",opts:["alto","alta","altos","altas"],ans:"alto",hint:"El estudiante is masculine singular. The adjective must agree."},
        {type:"fb",opts:["mejor","más bueno","bueno","más mejor"],hint:"The best restaurant. Use the irregular superlative form.",s:"Este es el {1} restaurante de la ciudad.",a:["mejor"]},
        {type:"mc",q:"María es ___ más inteligente del grupo.",opts:["el","la","las","los"],ans:"la",hint:"Maria is feminine singular. The article before mas must match."},
        {type:"fb",opts:["largo","larga","largos","corto"],hint:"The longest day. El dia is masculine, so the adjective must match.",s:"Es el dia más {1} del ano.",a:["largo"]},
        {type:"match",pairs:[{trg:"el mejor de",src:"the best of"},{trg:"la más alta de",src:"the tallest (f) of"},{trg:"el peor de",src:"the worst of"},{trg:"el más caro de",src:"the most expensive of"}]},
        {type:"drag_fill",hint:"Ana is the youngest in the class. Use the irregular superlative.",s:"Ana es {1} {2} {3} de la clase.",blanks:{"1":"la","2":"menor","3":"de"},pool:["la","menor","de","el","más"]},
        {type:"mc",q:"What does 'Es la pelicula más aburrida del ano' mean?",opts:["It is less boring than last year's movie","It is a more boring movie than last year","It is the most boring movie of the year","It is as boring as last year's movie"],ans:"It is the most boring movie of the year",hint:"La mas + adjective + de = the most + adjective + of/in."},
        {type:"fb",opts:["mayor","más vieja","menor","mejor"],hint:"The oldest in the family. Use the polite irregular superlative for age.",s:"Mi abuela es la {1} de la familia.",a:["mayor"]},
        {type:"mc",q:"¿Cuál es el mes más ___ del ano en Espana?",opts:["caliente","calurosa","calurosos","caluroso"],ans:"caluroso",hint:"El mes is masculine singular. Which adjective form means hot/warm and agrees?"},
        {type:"drag_fill",hint:"This is the cheapest product in the store.",s:"Este es {1} {2} {3} {4} la tienda.",blanks:{"1":"el","2":"producto","3":"más","4":"barato de"},pool:["el","producto","más","barato de","como","menos"]},
        {type:"fb",opts:["aburrida","aburrido","aburridos","divertida"],hint:"La pelicula is feminine singular. Which means boring and agrees?",s:"Es la pelicula más {1} del festival.",a:["aburrida"]},
        {type:"mc",q:"Mi padre es ___ de mis tios.",opts:["el mayor","el más viejo","más mayor","mayor de"],ans:"el mayor",hint:"The oldest among family members. Use the irregular superlative with the article."}
  ]},
  {id:"esp15l5",title:"Tanto...como",icon:"🤝",xp:20,board:true,steps:[
        {type:"intro",title:"Tanto...como",desc:"Learn to compare equal quantities using tanto/a/os/as...como (as much/many...as). Unlike tan (for adjectives), tanto changes form to match the noun.",goals:["Use tanto/a/os/as before nouns","Distinguish tan (adjectives) from tanto (nouns)","Compare quantities in everyday situations"]},
        {type:"teach",trg:"tanto...como",src:"as much...as",pos:"noun",gender:"m",phonetic:"TAHN-toh...KOH-moh",note:"Tanto + masculine uncountable noun + como. Tanto changes gender and number.",example:"A: ¿Tienes mucho trabajo?\nB: Si, tengo tanto trabajo como tu.\nA: ¡Necesitamos vacaciones!\nB: Si, tanto tu como yo.",exampleSrc:"A: Do you have a lot of work?\nB: Yes, I have as much work as you.\nA: We need a vacation!\nB: Yes, both you and I.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"tanta...como",src:"as much...as (feminine)",pos:"noun",gender:"f",phonetic:"TAHN-tah...KOH-moh",note:"Tanta + feminine uncountable noun + como. Matches feminine nouns.",example:"A: ¿Hay mucha gente en el concierto?\nB: Si, hay tanta gente como el ano pasado.\nA: ¿Encontramos sitio?\nB: No se, hay tanta gente que es dificil.",exampleSrc:"A: Are there many people at the concert?\nB: Yes, there are as many people as last year.\nA: Will we find a spot?\nB: I don't know, there are so many people it's difficult.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"tantos...como",src:"as many...as (masculine plural)",pos:"noun",gender:"m",phonetic:"TAHN-tohs...KOH-moh",note:"Tantos + masculine plural noun + como. For countable masculine nouns.",example:"A: ¿Tienes muchos libros?\nB: Si, tengo tantos libros como mi hermana.\nA: ¿Cuantos tienes?\nB: Más de doscientos.",exampleSrc:"A: Do you have many books?\nB: Yes, I have as many books as my sister.\nA: How many do you have?\nB: More than two hundred.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"tantas...como",src:"as many...as (feminine plural)",pos:"noun",gender:"f",phonetic:"TAHN-tahs...KOH-moh",note:"Tantas + feminine plural noun + como. For countable feminine nouns.",example:"A: ¿Ana tiene muchas amigas?\nB: Si, tiene tantas amigas como su hermana.\nA: Son muy sociables.\nB: Si, siempre están con gente.",exampleSrc:"A: Does Ana have many friends?\nB: Yes, she has as many friends as her sister.\nA: They are very sociable.\nB: Yes, they are always with people.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"tip",title:"Tan vs Tanto: the key difference",text:"TAN + adjective + como = as [adjective] as\n  Es tan alto como yo.\n\nTANTO/A/OS/AS + noun + como = as much/many [noun] as\n  Tengo tantos libros como tu. (masc. plural)\n  Hay tanta agua como ayer. (fem. singular)\n\nTanto changes to match the noun:\n  tanto (masc. sing.), tanta (fem. sing.)\n  tantos (masc. pl.), tantas (fem. pl.)"},
        {type:"mc",q:"Tengo ___ libros como tú.",opts:["tantos","tanto","tan","tantas"],ans:"tantos",hint:"Libros is masculine plural. The quantity word must match."},
        {type:"fb",opts:["tanta","tanto","tantos","tan"],hint:"Gente is feminine singular. The quantity word must agree.",s:"Hay {1} gente como ayer.",a:["tanta"]},
        {type:"mc",q:"Mi hermana tiene ___ amigas como yo.",opts:["tantos","tantas","tanta","tan"],ans:"tantas",hint:"Amigas is feminine plural. Which form matches?"},
        {type:"fb",opts:["tanto","tanta","tantos","tan"],hint:"Dinero is masculine singular. Choose the matching form.",s:"No tengo {1} dinero como Carlos.",a:["tanto"]},
        {type:"match",pairs:[{trg:"tanto trabajo como",src:"as much work as"},{trg:"tantas casas como",src:"as many houses as"},{trg:"tantos amigos como",src:"as many friends as"},{trg:"tanta agua como",src:"as much water as"}]},
        {type:"mc",q:"Which is correct? 'Mi ciudad tiene ___ parques como la tuya.'",opts:["tantas","tanto","tantos","tan"],ans:"tantos",hint:"Parques is masculine plural. The quantity word must agree."},
        {type:"drag_fill",hint:"She has as much patience as her mother. Paciencia is feminine.",s:"Ella tiene {1} {2} {3} su madre.",blanks:{"1":"tanta","2":"paciencia","3":"como"},pool:["tanta","paciencia","como","tantos","que"]},
        {type:"fb",opts:["tantos","tantas","tanto","tan"],hint:"Coches is masculine plural. Which form of tanto matches?",s:"Hay {1} coches como motos en la calle.",a:["tantos"]},
        {type:"mc",q:"What does 'No hay tantas tiendas como en Madrid' mean?",opts:["The stores are as big as in Madrid","There are more stores than in Madrid","There are fewer stores than in Madrid","There aren't as many stores as in Madrid"],ans:"There aren't as many stores as in Madrid",hint:"Tantas...como expresses equal quantity. No negates it."},
        {type:"drag_fill",hint:"Pedro eats as much bread as his brother. Pan is masculine singular.",s:"Pedro come {1} {2} {3} su hermano.",blanks:{"1":"tanto","2":"pan","3":"como"},pool:["tanto","pan","como","tantos","que"]},
        {type:"fb",opts:["tantos","tantas","tanto","tan"],hint:"Chicos is masculine plural. The quantity word must match.",s:"En esta clase hay {1} chicos como chicas.",a:["tantos"]},
        {type:"mc",q:"Ella no bebe ___ agua como su hermana.",opts:["tanta","tanto","tantas","tan"],ans:"tanta",hint:"Agua is feminine (even though it uses el agua). The quantity word is feminine singular."}
  ]},
  {id:"esp15l6",title:"Concordancia de adjetivos",icon:"🔄",xp:20,board:true,steps:[
        {type:"intro",title:"Adjective Agreement Review",desc:"Review how Spanish adjectives change form to match the noun they describe in gender (masculine/feminine) and number (singular/plural). This is essential for correct comparisons.",goals:["Match adjectives to nouns in gender and number","Handle adjectives ending in -e and consonants","Apply agreement in comparison sentences"]},
        {type:"teach",trg:"-o/-a/-os/-as adjectives",src:"four-form adjectives",pos:"adj",gender:null,phonetic:"",note:"Most adjectives have 4 forms: rojo/roja/rojos/rojas.",example:"A: ¿Tu gato es blanco?\nB: No, es negro. Y mi gata es negra.\nA: ¿Y los gatitos?\nB: Los gatitos son blancos y negros.",exampleSrc:"A: Is your cat white?\nB: No, he is black. And my female cat is black.\nA: And the kittens?\nB: The kittens are black and white.",funFact:"Spanish adjectives agree in gender and number. Most change -o/-a for gender and add -s for plural."},
        {type:"teach",trg:"-e adjectives",src:"two-form adjectives (ending in -e)",pos:"noun",gender:"m",phonetic:"",note:"Adjectives ending in -e: same for masc/fem. Add -s for plural: grande/grandes.",example:"A: ¿Es grande tu casa?\nB: Si, es bastante grande.\nA: ¿Y las habitaciones?\nB: Las habitaciones son grandes tambien.",exampleSrc:"A: Is your house big?\nB: Yes, it is quite big.\nA: And the rooms?\nB: The rooms are big too.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"-consonant adjectives",src:"two-form adjectives (ending in consonant)",pos:"noun",gender:"m",phonetic:"",note:"Adjectives ending in consonant: same for masc/fem. Add -es for plural: facil/faciles.",example:"A: ¿El examen fue dificil?\nB: Si, fue muy dificil.\nA: ¿Y las preguntas?\nB: Las preguntas fueron dificiles.",exampleSrc:"A: Was the exam difficult?\nB: Yes, it was very difficult.\nA: And the questions?\nB: The questions were difficult.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"tip",title:"Adjective agreement summary",text:"4-form (-o ending): alto/alta/altos/altas\n2-form (-e ending): grande/grandes\n2-form (consonant): facil/faciles, feliz/felices\n\nThe adjective ALWAYS matches the noun:\n  La casa roja (fem. sing.)\n  Los coches rojos (masc. pl.)\n  Las chicas inteligentes (fem. pl.)\n  El examen dificil (masc. sing.)"},
        {type:"teach",trg:"feliz",src:"happy",pos:"adj",gender:null,phonetic:"feh-LEES",note:"feliz/felices. Same for masculine and feminine. Plural changes z to c.",example:"A: ¿Estas feliz con tu trabajo nuevo?\nB: Si, estoy muy feliz.\nA: ¿Y tus companeros?\nB: Todos estamos felices.",exampleSrc:"A: Are you happy with your new job?\nB: Yes, I am very happy.\nA: And your coworkers?\nB: We are all happy.",funFact:"Spanish adjectives agree in gender and number. Most change -o/-a for gender and add -s for plural."},
        {type:"mc",q:"Las flores son más ___ que las hojas.",opts:["bonitas","bonitos","bonita","bonito"],ans:"bonitas",hint:"Las flores is feminine plural. The adjective must match."},
        {type:"fb",opts:["felices","feliz","felizes","contentos"],hint:"Los ninos is masculine plural. Feliz becomes what in plural?",s:"Los ninos son más {1} que los adultos.",a:["felices"]},
        {type:"mc",q:"Estas sillas son tan ___ como las otras.",opts:["comodo","comodas","comodos","comoda"],ans:"comodas",hint:"Estas sillas is feminine plural. The adjective must agree."},
        {type:"fb",opts:["dificil","dificiles","dificila","facil"],hint:"La leccion is feminine singular. Adjectives ending in a consonant keep the same form for both genders.",s:"La leccion es menos {1} que la anterior.",a:["dificil"]},
        {type:"match",pairs:[{trg:"chica alta",src:"tall girl"},{trg:"chicos altos",src:"tall boys"},{trg:"casa grande",src:"big house"},{trg:"problemas dificiles",src:"difficult problems"}]},
        {type:"drag_fill",hint:"Red apples are sweeter than green ones. All feminine plural.",s:"Las manzanas {1} son más {2} que las {3}.",blanks:{"1":"rojas","2":"dulces","3":"verdes"},pool:["rojas","dulces","verdes","rojo","dulce"]},
        {type:"mc",q:"Mi hermana es más ___ que mi hermano.",opts:["trabajadores","trabajador","trabajadora","trabajadoras"],ans:"trabajadora",hint:"Mi hermana is feminine singular. The adjective ending in -or adds -a for feminine."},
        {type:"fb",opts:["inteligentes","inteligente","inteligenta","inteligento"],hint:"Los gatos is masculine plural. Inteligente adds -s for plural.",s:"Los gatos son tan {1} como los perros.",a:["inteligentes"]},
        {type:"mc",q:"Estas preguntas son las más ___ del examen.",opts:["facilos","facil","facilas","faciles"],ans:"faciles",hint:"Estas preguntas is feminine plural. Consonant-ending adjectives add -es for plural, with no separate feminine form."},
        {type:"drag_fill",hint:"Spanish restaurants are more famous than Italian ones. All masculine plural.",s:"Los restaurantes {1} son {2} {3} que los {4}.",blanks:{"1":"espanoles","2":"más","3":"famosos","4":"italianos"},pool:["espanoles","más","famosos","italianos","espanola","famosa"]},
        {type:"mc",q:"Los zapatos ___ son más ___ que los zapatos ___.",opts:["negros...comodos...blancos","negro...comodo...blanco","negras...comodas...blancas","negra...comoda...blanca"],ans:"negros...comodos...blancos",hint:"Los zapatos is masculine plural. All adjectives must be masculine plural."},
        {type:"fb",opts:["europeas","europeos","europea","europeo"],hint:"Las ciudades is feminine plural. The adjective describing them must match.",s:"Las ciudades {1} son más grandes que las ciudades pequenas.",a:["europeas"]}
  ]},
  {id:"esp15l7",title:"Comparar todo",icon:"🌍",xp:20,board:true,steps:[
        {type:"intro",title:"Comparing Everything",desc:"Put all comparison structures together. Compare people, places, and things using mas...que, menos...que, tan...como, tanto...como, superlatives, and irregular forms.",goals:["Combine all comparison types in context","Express preferences through comparisons","Describe people, places, and things comparatively"]},
        {type:"teach",trg:"Me gusta más...que",src:"I like...more than",pos:"noun",gender:null,phonetic:"meh GOOS-tah mahs...keh",note:"Me gusta mas + noun + que + noun. A common way to express preferences.",example:"A: ¿Que te gusta más, el cafe o el te?\nB: Me gusta más el cafe que el te.\nA: ¿Y el chocolate?\nB: El chocolate me gusta más que los dos.",exampleSrc:"A: What do you like more, coffee or tea?\nB: I like coffee more than tea.\nA: And chocolate?\nB: I like chocolate more than both.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"Prefiero...a",src:"I prefer...to",pos:"noun",gender:null,phonetic:"preh-FYEH-roh...ah",note:"Prefiero + noun + a + noun. Another way to compare preferences.",example:"A: ¿Prefieres la playa o la montana?\nB: Prefiero la playa a la montana.\nA: ¿Por que?\nB: Porque me gusta más el calor que el frio.",exampleSrc:"A: Do you prefer the beach or the mountain?\nB: I prefer the beach to the mountain.\nA: Why?\nB: Because I like heat more than cold.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"tranquilo",src:"quiet, calm",pos:"noun",gender:null,phonetic:"trahn-KEE-loh",note:"tranquilo/tranquila. Describes places, people, and atmospheres.",example:"A: ¿Te gusta vivir en el campo?\nB: Si, es más tranquilo que la ciudad.\nA: ¿No te aburres?\nB: No, prefiero la tranquilidad al ruido.",exampleSrc:"A: Do you like living in the countryside?\nB: Yes, it is calmer than the city.\nA: Don't you get bored?\nB: No, I prefer tranquility to noise.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"barato",src:"cheap, inexpensive",pos:"noun",gender:null,phonetic:"bah-RAH-toh",note:"barato/barata. The opposite of caro (expensive).",example:"A: ¿Es barato comer aqui?\nB: Si, es más barato que el restaurante de al lado.\nA: ¿Y la calidad?\nB: Es tan buena como la del otro.",exampleSrc:"A: Is it cheap to eat here?\nB: Yes, it is cheaper than the restaurant next door.\nA: And the quality?\nB: It is as good as the other one.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"tip",title:"Combining comparison structures",text:"Use different structures for variety:\n\nPreference: Me gusta mas el cafe que el te.\nEquality: Madrid es tan bonita como Barcelona.\nSuperiority: El tren es mas rapido que el autobus.\nInferiority: El pueblo es menos ruidoso que la ciudad.\nSuperlative: Es el mejor restaurante de la zona.\nIrregular: Mi hermano mayor es mejor cocinero."},
        {type:"mc",q:"Me gusta más la playa ___ la montana.",opts:["que","como","de","a"],ans:"que",hint:"With me gusta mas, we compare using a specific word."},
        {type:"fb",opts:["interesante","interesantes","interesar","interesada"],hint:"Madrid is as interesting as Barcelona. Both cities are singular.",s:"Madrid es tan {1} como Barcelona.",a:["interesante"]},
        {type:"mc",q:"¿Cuál es la ciudad más ___ de Espana?",opts:["grandes","grande","mayor","gran"],ans:"grande",hint:"For physical size of a city, we use the regular adjective form with superlative."},
        {type:"drag_fill",hint:"The countryside is calmer than the city.",s:"El campo es {1} {2} {3} la ciudad.",blanks:{"1":"más","2":"tranquilo","3":"que"},pool:["más","tranquilo","que","tan","como"]},
        {type:"fb",opts:["a","que","como","de"],hint:"With prefiero, we use a specific preposition before the second item.",s:"Prefiero el verano {1} el invierno.",a:["a"]},
        {type:"match",pairs:[
          {trg:"Me gusta más el sol",src:"I like the sun more"},
          {trg:"Prefiero la montana",src:"I prefer the mountain"},
          {trg:"Es tan bonito como",src:"It is as pretty as"},
          {trg:"Es el mejor de todos",src:"It is the best of all"}
        ]},
        {type:"mc",q:"A: ¿Qué ciudad ofrece más calidad de vida? B: Creo que Valencia es ___ para vivir que Madrid.",opts:["buena","más buena","mejor","la mejor"],ans:"mejor",hint:"Comparative of bueno is irregular. Never combine 'más' with the irregular form."},
        {type:"drag_fill",hint:"This hotel is the cheapest in the area. Superlative structure.",s:"Este hotel es {1} {2} {3} {4} la zona.",blanks:{"1":"el","2":"más","3":"barato","4":"de"},pool:["el","más","barato","de","que","como"]},
        {type:"fb",opts:["mejor","más buena","buena","peor"],hint:"My mother cooks better. Use the irregular comparative.",s:"Mi madre cocina {1} que mi padre.",a:["mejor"]},
        {type:"mc",q:"What does 'No hay nada peor que llegar tarde' mean?",opts:["Arriving late is as bad as leaving early","There is nothing better than arriving late","It is less bad to arrive late","There is nothing worse than arriving late"],ans:"There is nothing worse than arriving late",hint:"Peor = ___. Nada peor que = ___ ___ than."},
        {type:"drag_fill",hint:"Winter is less hot than summer.",s:"El invierno es {1} {2} {3} el verano.",blanks:{"1":"menos","2":"caluroso","3":"que"},pool:["menos","caluroso","que","más","como"]},
        {type:"fb",opts:["que","como","de","a"],hint:"I like chocolate more THAN coffee. Which comparison word follows mas?",s:"El chocolate me gusta más {1} el cafe.",a:["que"]}
  ]},
  {id:"esp15l8",title:"Repaso: Comparaciones",icon:"📝",xp:25,board:true,steps:[
        {type:"intro",title:"Review: Comparisons",desc:"Review and practice all comparison structures from this unit: mas...que, menos...que, tan...como, tanto/a/os/as...como, irregular comparatives, and superlatives.",goals:["Use all comparison structures confidently","Choose the right structure for each context","Combine comparisons with correct adjective agreement"]},
        {type:"mc",q:"El tren es ___ rápido ___ el avion.",opts:["menos...que","menos...como","tan...que","más...de"],ans:"menos...que",hint:"Less...than. Remember which word follows the adjective in this structure."},
        {type:"fb",opts:["inteligente","inteligentes","inteligenta","mejor"],hint:"The most intelligent. Superlative with a regular adjective. Feminine singular.",s:"Maria es la más {1} de la clase.",a:["inteligente"]},
        {type:"mc",q:"Tengo ___ amigos como tú.",opts:["tanto","tantos","tan","tantas"],ans:"tantos",hint:"Amigos is masculine plural. The quantity word must agree."},
        {type:"drag_fill",hint:"This restaurant is better than the other one. Irregular comparative.",s:"Este restaurante es {1} {2} el otro.",blanks:{"1":"mejor","2":"que"},pool:["mejor","que","más","bueno","como"]},
        {type:"fb",opts:["mayor","más viejo","menor","mejor"],hint:"The oldest in the family. Use the polite irregular form for age.",s:"Mi abuelo es el {1} de la familia.",a:["mayor"]},
        {type:"match",pairs:[{trg:"más alto que",src:"taller than"},{trg:"tan grande como",src:"as big as"},{trg:"el mejor de",src:"the best of"},{trg:"tantas casas como",src:"as many houses as"}]},
        {type:"mc",q:"Las naranjas son más ___ que los limones.",opts:["dulca","dulce","dulces","dulcos"],ans:"dulces",hint:"Las naranjas is feminine plural. Dulce ends in -e, so it just adds -s."},
        {type:"drag_fill",hint:"There is nothing better than my grandmother's food.",s:"No hay {1} {2} {3} la comida de mi abuela.",blanks:{"1":"nada","2":"mejor","3":"que"},pool:["nada","mejor","que","más","como"]},
        {type:"fb",opts:["tanta","tanto","tantos","tan"],hint:"Gente is feminine singular. The quantity word must match.",s:"Hay {1} gente hoy como ayer.",a:["tanta"]},
        {type:"mc",q:"¿Cuál es la traduccion correcta de 'She is as tall as her brother'?",opts:["Ella es tanta alta como su hermano","Ella es más alta que su hermano","Ella es tanto alta como su hermano","Ella es tan alta como su hermano"],ans:"Ella es tan alta como su hermano",hint:"With adjectives we use ___...___, not ___to. And ___ agrees with ___."},
        {type:"drag_fill",hint:"Madrid is the biggest city in Spain. Superlative structure.",s:"Madrid es la ciudad {1} {2} {3} Espana.",blanks:{"1":"más","2":"grande","3":"de"},pool:["más","grande","de","que","como"]},
        {type:"fb",opts:["peor","más malo","malo","mejor"],hint:"This exam is worse. Use the irregular comparative form.",s:"Este examen es {1} que el anterior.",a:["peor"]},
        {type:"mc",q:"Mi hermana tiene tantas ___ como yo.",opts:["ideas","idea","ideos","ideaas"],ans:"ideas",hint:"Tantas matches a feminine plural noun. What is the plural of idea?"},
        {type:"match",pairs:[{trg:"menos dificil que",src:"less difficult than"},{trg:"la peor de",src:"the worst (f) of"},{trg:"tantos problemas como",src:"as many problems as"},{trg:"el más barato de",src:"the cheapest of"}]},
        {type:"drag_fill",hint:"Ana is as tall as Pedro but shorter than Luis.",s:"Ana es {1} {2} {3} Pedro pero {4} que Luis.",blanks:{"1":"tan","2":"alta","3":"como","4":"más baja"},pool:["tan","alta","como","más baja","menos","que"]},
        {type:"mc",q:"Which sentence is INCORRECT?",opts:["Es mejor que el otro","Es más mejor que el otro","Es más caro que el otro","Es tan bueno como el otro"],ans:"Es más mejor que el otro",hint:"One sentence incorrectly combines mas with an irregular comparative."},
        {type:"fb",opts:["bonitas","bonita","bonitos","bonito"],hint:"Ciudades is feminine plural. The adjective in the superlative must agree.",s:"Barcelona es una de las ciudades más {1} de Europa.",a:["bonitas"]},
        {type:"mc",q:"What does 'No tengo tanto tiempo como antes' mean?",opts:["I have as much time as before","I don't have more time than before","I don't have as much time as before","I have more time than before"],ans:"I don't have as much time as before",hint:"Tanto...como = as ___...as. No negates the equality."}
  ]},
  {id:"esp15l_verb",title:"Verbos para debatir",icon:"💬",xp:15,board:true,steps:[
    {type:"intro",title:"B1 Civic Debate Verbs",desc:"Learn 7 essential B1 Spanish verbs for discussing ideas: to debate, to raise an issue, to question, to counter-argue, to conclude, to summarize, and to negotiate. Essential for DELE B1 speaking and writing tasks.",goals:["Master 7 core B1 civic verbs","Use them in formal discussion","Express disagreement politely"]},
    {type:"teach",trg:"debatir",src:"to debate",pos:"verb",gender:null,
     note:"Regular -ir verb: debato, debates, debate, debatimos, debaten. Used for structured, public-style discussion.",
     example:"A: ¿Sobre qué debatís hoy en clase?\nB: Debatimos sobre el uso del móvil en el aula.\nA: ¿Y cuál es tu postura?\nB: Creo que hay que debatirlo con calma.",
     exampleSrc:"A: What are you debating in class today?\nB: We are debating the use of mobile phones in class.\nA: And what is your position?\nB: I think we need to debate it calmly.",
     funFact:"From Latin 'debattuere' (to beat down). The same root gives English 'debate'. One of only a handful of direct Latin borrowings shared by both languages unchanged."},
    {type:"teach",trg:"plantear",src:"to raise (an issue) / to put forward",pos:"verb",gender:null,
     note:"Regular -ar verb: planteo, planteas, plantea. Means to introduce a topic or problem into discussion.",
     example:"A: ¿Quién plantea el primer punto?\nB: Yo planteo la cuestión del precio.\nA: Buena idea. Es un tema importante.\nB: También quiero plantear el tema del transporte.",
     exampleSrc:"A: Who raises the first point?\nB: I raise the question of price.\nA: Good idea. It is an important topic.\nB: I also want to raise the topic of transport.",
     funFact:"From 'planta' (plant/sole). The image is of 'planting' an idea firmly on the table, making it impossible to ignore."},
    {type:"teach",trg:"cuestionar",src:"to question / to challenge",pos:"verb",gender:null,
     note:"Regular -ar verb: cuestiono, cuestionas, cuestiona. Used to challenge an assumption or claim.",
     example:"A: Hay que cuestionar esa idea.\nB: ¿Por qué la cuestionas?\nA: Porque no tenemos datos suficientes.\nB: Tienes razón. Debemos cuestionarla mejor.",
     exampleSrc:"A: We need to question that idea.\nB: Why do you question it?\nA: Because we don't have enough data.\nB: You are right. We should question it more carefully.",
     funFact:"Derived from 'cuestión' (question), which comes from Latin 'quaestio'. The -ar suffix makes any noun into a verb: 'cuestión' becomes 'cuestionar'. English uses the same trick: question becomes 'to question'."},
    {type:"teach",trg:"rebatir",src:"to counter-argue / to rebut",pos:"verb",gender:null,
     note:"Regular -ir verb: rebato, rebates, rebate. Used to directly oppose and disprove an argument.",
     example:"A: ¿Cómo puedo rebatir ese argumento?\nB: Puedes rebatirlo con datos concretos.\nA: Pero él rebate todos mis ejemplos.\nB: Entonces rebate su premisa principal.",
     exampleSrc:"A: How can I counter-argue that point?\nB: You can rebut it with concrete data.\nA: But he counters all my examples.\nB: Then rebut his main premise.",
     funFact:"From Latin 're-' (again, back) + 'battuere' (to beat). Literally to beat something back. Its English cousin is 'rebut', used in legal and academic contexts."},
    {type:"teach",trg:"concluir",src:"to conclude",pos:"verb",gender:null,
     note:"Irregular -ir verb (like construir): concluyo, concluyes, concluye. Add -y- before vowel endings.",
     example:"A: ¿A qué conclusión llegáis?\nB: Concluimos que el proyecto es viable.\nA: ¿Y el equipo B, qué concluye?\nB: También concluye que es posible hacerlo.",
     exampleSrc:"A: What conclusion do you reach?\nB: We conclude that the project is viable.\nA: And team B, what do they conclude?\nB: They also conclude that it is possible.",
     funFact:"From Latin 'concludere' (to shut, to end). The -uir verb group (concluir, construir, destruir) always inserts a 'y' before an unstressed 'e' or 'a'. Remember: the 'y' keeps these verbs from clashing syllables."},
    {type:"teach",trg:"resumir",src:"to summarize",pos:"verb",gender:null,
     note:"Regular -ir verb: resumo, resumes, resume. Often used to close a speech or presentation.",
     example:"A: Por favor, resume los puntos principales.\nB: Resumiendo: más tiempo, más recursos y mejor comunicación.\nA: Perfecto. ¿Alguien quiere añadir algo?\nB: Creo que has resumido todo muy bien.",
     exampleSrc:"A: Please summarize the main points.\nB: To summarize: more time, more resources and better communication.\nA: Perfect. Does anyone want to add anything?\nB: I think you have summarized everything very well.",
     funFact:"From Latin 'resumere' (to take up again). 'Resumir' and the English 'resume' (noun for a CV) share the same root, but in Spanish the verb is used only for summarizing, never for a career document."},
    {type:"teach",trg:"negociar",src:"to negotiate",pos:"verb",gender:null,
     note:"Regular -ar verb: negocio, negocias, negocia. Used in professional, political, and everyday contexts.",
     example:"A: ¿Han podido negociar un acuerdo?\nB: Todavía negociamos. Es complicado.\nA: ¿Qué aspecto es más difícil de negociar?\nB: El precio es siempre lo más difícil de negociar.",
     exampleSrc:"A: Have they been able to negotiate an agreement?\nB: We are still negotiating. It is complicated.\nA: Which aspect is hardest to negotiate?\nB: The price is always the hardest thing to negotiate.",
     funFact:"From Latin 'negotium' (business, no-leisure: 'nec' + 'otium'). The ancient Romans had a word for the absence of leisure, and it became the basis for all commerce and deal-making in modern Romance languages."},
    {type:"tip",title:"Formal register in debate",text:"In DELE B1 spoken and written tasks, these verbs signal academic register:\n\ndebatir: to exchange opposing views in a structured way\nplantear: to introduce a topic or question\ncuestionar: to challenge an assumption\nrebatir: to counter a specific argument\nconcluir: to draw a conclusion\nresumir: to recap before closing\nnegociar: to find a middle position\n\nUsing these in writing (e.g. Se puede cuestionar que...) elevates your score from B1 to near-B2.",deepDive:{title:"Useful debate phrases",text:"Quiero plantear una cuestión: I want to raise a question.\nPodemos cuestionar si...: We can question whether...\nHay que rebatir ese punto: We must counter that point.\nPara concluir, resumo...: To conclude, I summarize...\nDebemos negociar una solución: We must negotiate a solution."}},
    {type:"mc",q:"A: ¿Quién plantea el primer punto? B: ___",opts:["Yo lo planteo ahora","Yo lo canto ahora","Yo lo compro ahora","Yo lo vendo ahora"],ans:"Yo lo planteo ahora",hint:"plantear = to raise or put forward a topic. Think of the response that uses the same verb."},
    {type:"fb",opts:["debatir","cantar","correr","comprar"],hint:"To debate: a structured exchange of opposing views on a topic.",s:"Vamos a {1} el tema del cambio climático.",a:["debatir"]},
    {type:"mc",q:"Choose the correct definition of 'rebatir'.",opts:["to summarize a discussion","to counter-argue a point","to introduce a topic","to reach an agreement"],ans:"to counter-argue a point",hint:"Re- means 'back'. rebatir = to hit back at an argument."},
    {type:"fb",opts:["cuestionar","negociar","resumir","concluir"],hint:"To challenge or call into question an assumption someone has made.",s:"Hay que {1} esa idea porque no hay datos que la apoyen.",a:["cuestionar"]},
    {type:"mc",q:"A: Para cerrar la reunión, ¿puedes hacer un resumen? B: Claro, ___",opts:["resumo los tres puntos principales","debato los tres puntos","planteo los tres puntos","negocios los tres puntos"],ans:"resumo los tres puntos principales",hint:"The request was to summarize. Which response uses the matching verb in first person?"},
    {type:"fb",opts:["concluir","plantear","rebatir","negociar"],hint:"When a debate ends, you draw a conclusion. Which verb means exactly that?",s:"Después de debatir, podemos {1} que la propuesta es viable.",a:["concluir"]},
    {type:"match",pairs:[
      {trg:"debatir",src:"to debate"},
      {trg:"plantear",src:"to raise an issue"},
      {trg:"rebatir",src:"to counter-argue"},
      {trg:"negociar",src:"to negotiate"}
    ]},
    {type:"fb",opts:["negociar","debatir","cuestionar","resumir"],hint:"Two sides want different things. They talk to find a middle position. Which verb fits?",s:"Tenemos que {1} un acuerdo entre las dos partes.",a:["negociar"]},
    {type:"mc",q:"Which verb means to summarize at the end of a speech?",opts:["cuestionar","plantear","resumir","debatir"],ans:"resumir",hint:"Think of what a speaker does in the final minute: they recap all key points."},
    {type:"drag_fill",hint:"I want to raise the topic of price so we can debate it and then conclude.",s:"Quiero {1} el tema del precio para {2}lo y luego {3}.",blanks:{"1":"plantear","2":"debatir","3":"concluir"},pool:["plantear","debatir","concluir","negociar","resumir"]}
  ]},
  {id:"esp15l8b",title:"El Transporte",icon:"🚌",xp:15,board:true,steps:[
        {type:"intro",title:"El Transporte",desc:"Learn how to talk about transportation, tickets, and getting around in Spanish.",goals:["Learn 15 transport words with el/la","Use ir en + vehicle for travel","Understand billete (Spain) vs boleto (Latin America)"]},
        {type:"teach",trg:"el autobús",src:"the bus",pos:"noun",gender:"m",phonetic:"el ow-toh-BOOS",note:"el autobús: masculine.\nPlural: los autobuses.\nIr en autobús = to go by bus.",example:"A: ¿Cómo vas al trabajo?\nB: Voy en autobús.\nA: ¿A qué hora sale?\nB: Sale a las siete y media.",exampleSrc:"A: How do you get to work?\nB: I go by bus.\nA: What time does it leave?\nB: It leaves at seven thirty.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el metro",src:"the subway / metro",pos:"noun",gender:"m",phonetic:"el MEH-troh",note:"el metro: masculine.\nTomar el metro = to take the subway.\nAlso means 'meter' (unit of length).",example:"A: ¿Hay metro en tu ciudad?\nB: Sí, tiene diez líneas.\nA: ¿Es rápido?\nB: Sí, es más rápido que el autobús.",exampleSrc:"A: Is there a metro in your city?\nB: Yes, it has ten lines.\nA: Is it fast?\nB: Yes, it's faster than the bus.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el taxi",src:"the taxi",pos:"noun",gender:"m",phonetic:"el TAK-see",note:"el taxi: masculine.\nTomar un taxi = to take a taxi.\nEl/la taxista = the taxi driver.",example:"A: Necesito un taxi al aeropuerto.\nB: ¿A qué hora es tu vuelo?\nA: A las tres de la tarde.\nB: Entonces pide el taxi para la una.",exampleSrc:"A: I need a taxi to the airport.\nB: What time is your flight?\nA: At three in the afternoon.\nB: Then order the taxi for one o'clock.",funFact:"Cognate with English 'taxi'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"el tren",src:"the train",pos:"noun",gender:"m",phonetic:"el tren",note:"el tren: masculine.\nPlural: los trenes.\nIr en tren = to go by train.",example:"A: ¿Prefieres el tren o el avión?\nB: El tren, porque puedo ver el paisaje.\nA: Es verdad, y es más cómodo.\nB: Además es mejor para el medio ambiente.",exampleSrc:"A: Do you prefer the train or the plane?\nB: The train, because I can see the landscape.\nA: That's true, and it's more comfortable.\nB: Also it's better for the environment.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el avión",src:"the airplane",pos:"noun",gender:"m",phonetic:"el ah-VYOHN",note:"el avión: masculine.\nPlural: los aviones.\nVolar en avión = to fly by plane.",example:"A: ¿Cuánto cuesta un vuelo a Madrid?\nB: Depende de la fecha.\nA: Para julio.\nB: En verano los aviones están más caros.",exampleSrc:"A: How much does a flight to Madrid cost?\nB: It depends on the date.\nA: For July.\nB: In summer planes are more expensive.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"la bicicleta",src:"the bicycle",pos:"noun",gender:"f",phonetic:"lah bee-thee-KLEH-tah",note:"la bicicleta: feminine.\nShort form: la bici.\nIr en bicicleta = to go by bike.",example:"A: ¿Vas en bicicleta al trabajo?\nB: Sí, todos los días.\nA: ¿No es cansado?\nB: Un poco, pero es bueno para la salud.",exampleSrc:"A: Do you ride your bike to work?\nB: Yes, every day.\nA: Isn't it tiring?\nB: A little, but it's good for your health.",funFact:"Cognate with English 'bicycle'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"el barco",src:"the boat / ship",pos:"noun",gender:"m",phonetic:"el BAR-koh",note:"el barco: masculine.\nPlural: los barcos.\nEl crucero = cruise ship.",example:"A: ¿Has viajado en barco alguna vez?\nB: Sí, de Barcelona a Mallorca.\nA: ¿Cuánto tiempo tardó?\nB: Unas seis horas.",exampleSrc:"A: Have you ever traveled by boat?\nB: Yes, from Barcelona to Mallorca.\nA: How long did it take?\nB: About six hours.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"la estación",src:"the station",pos:"noun",gender:"f",phonetic:"lah es-tah-THYOHN",note:"la estación: feminine.\nLa estación de tren = train station.\nAlso means 'season' (la estación del año).",example:"A: ¿Dónde está la estación de tren?\nB: Está al final de esta calle.\nA: ¿Está lejos?\nB: No, la estación está muy cerca.",exampleSrc:"A: Where is the train station?\nB: It's at the end of this street.\nA: Is it far?\nB: No, the station is very close.",funFact:"Cognate with English 'station'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"la parada de autobús",src:"the bus stop",pos:"noun",gender:"f",phonetic:"lah pah-RAH-dah deh ow-toh-BOOS",note:"la parada: feminine (the stop).\nLa parada de metro = metro stop.\nParar = to stop.",example:"A: ¿Hay una parada de autobús cerca?\nB: Sí, en la esquina.\nA: ¿Cada cuánto pasa el autobús?\nB: Cada diez minutos.",exampleSrc:"A: Is there a bus stop nearby?\nB: Yes, on the corner.\nA: How often does the bus come?\nB: Every ten minutes.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"el aeropuerto",src:"the airport",pos:"noun",gender:"m",phonetic:"el ah-eh-roh-PWER-toh",note:"el aeropuerto: masculine.\naero (air) + puerto (port).\nLlegar al aeropuerto = to arrive at the airport.",example:"A: ¿Cómo llego al aeropuerto?\nB: Puedes tomar el metro, línea tres.\nA: ¿Cuánto tarda?\nB: Unos cuarenta minutos desde el centro.",exampleSrc:"A: How do I get to the airport?\nB: You can take the metro, line three.\nA: How long does it take?\nB: About forty minutes from the center.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el billete",src:"the ticket",pos:"noun",gender:"m",phonetic:"el bee-YEH-teh",note:"el billete: masculine (Spain).\nel boleto: masculine (Latin America).\nBillete de ida = one-way ticket.\nBillete de ida y vuelta = round trip.",example:"A: ¿Dónde puedo comprar un billete?\nB: En la taquilla o por internet.\nA: ¿Cuánto cuesta un billete de ida?\nB: Quince euros.",exampleSrc:"A: Where can I buy a ticket?\nB: At the ticket office or online.\nA: How much is a one-way ticket?\nB: Fifteen euros.",deepDive:{
          title:"Billete vs Boleto",
          text:"In Spain, 'el billete' is used for transport tickets and banknotes. In Latin America, 'el boleto' is more common for tickets, while 'el billete' refers mainly to banknotes. Both are correct and widely understood."
        ,funFact:"Masculine noun. Spanish words ending in -o are usually masculine."}},
        {type:"teach",trg:"la línea",src:"the line / route",pos:"noun",gender:"f",phonetic:"lah LEE-neh-ah",note:"la línea: feminine.\nLa línea de autobús = bus route.\nLa línea de metro = metro line.",example:"A: ¿Qué línea de metro va al centro?\nB: La línea dos, la roja.\nA: ¿Tengo que hacer transbordo?\nB: No, es directo.",exampleSrc:"A: Which metro line goes to the center?\nB: Line two, the red one.\nA: Do I have to transfer?\nB: No, it's direct.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"hacer transbordo",src:"to transfer (change vehicle)",pos:"verb",gender:null,phonetic:"ah-THER trans-BOR-doh",note:"Hacer transbordo = to change trains/buses.\nTransbordo = transfer.\nCambiar de tren also works.",example:"A: ¿Tengo que hacer transbordo?\nB: Sí, en la estación Sol.\nA: ¿A qué línea?\nB: A la línea cinco.",exampleSrc:"A: Do I have to transfer?\nB: Yes, at Sol station.\nA: To which line?\nB: To line five.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"teach",trg:"la salida",src:"the departure / exit",pos:"noun",gender:"f",phonetic:"lah sah-LEE-dah",note:"la salida: feminine.\nHora de salida = departure time.\nAlso means 'exit' (salida de emergencia).",example:"A: ¿A qué hora es la salida del tren?\nB: A las nueve en punto.\nA: ¿Desde qué andén?\nB: Andén número tres.",exampleSrc:"A: What time is the train's departure?\nB: At nine o'clock sharp.\nA: From which platform?\nB: Platform number three.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"la llegada",src:"the arrival",pos:"noun",gender:"f",phonetic:"lah yeh-GAH-dah",note:"la llegada: feminine.\nHora de llegada = arrival time.\nLlegar = to arrive.",example:"A: ¿A qué hora es la llegada?\nB: El tren llega a las once.\nA: Perfecto, te espero en la estación.\nB: ¡Gracias!",exampleSrc:"A: What time is the arrival?\nB: The train arrives at eleven.\nA: Perfect, I'll wait for you at the station.\nB: Thanks!",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"tip",title:"Ir en + transporte",deepDive:{
          title:"Exceptions and Variations",
          text:"Ir en coche = go by car. Ir en barco = go by boat. Ir en taxi = go by taxi. Ir en metro = go by metro. The only common exception is 'ir a pie' (to go on foot) and 'ir a caballo' (to go on horseback), which use 'a' instead of 'en'."
        },text:"In Spanish, use 'ir en' with most vehicles:\nir en autobús = go by bus\nir en tren = go by train\nir en avión = go by plane\nir en bicicleta = go by bike\nBut: ir a pie = go on foot (no 'en')."},
        {type:"mc",q:"What is 'the bus' in Spanish?",opts:["el autobús","la autobús","el metro","la estación"],ans:"el autobús",hint:"A large vehicle that carries many passengers along a fixed route. Masculine noun."},
        {type:"fb",opts:["metro","taxi","pie","barco"],hint:"An underground train system found in big cities. Faster than surface transport.",s:"Voy al trabajo en {1} porque es más rápido que el autobús.",a:"metro"},
        {type:"mc",q:"What is the difference between 'el billete' and 'el boleto'?",opts:["billete is cheap, boleto is expensive","billete is Spain, boleto is Latin America","billete is for trains, boleto is for planes","They have completely different meanings"],ans:"billete is Spain, boleto is Latin America",hint:"Both mean ticket. The difference is regional, not about the type of transport."},
        {type:"match",pairs:[{trg:"el tren",src:"train"},{trg:"el avión",src:"airplane"},{trg:"la bicicleta",src:"bicycle"},{trg:"el barco",src:"boat"},{trg:"el taxi",src:"taxi"}]},
        {type:"fb",opts:["parada","estación","línea","salida"],hint:"The place where you wait for the bus to stop and pick you up.",s:"¿Dónde está la {1} de autobús más cercana?",a:"parada"},
        {type:"mc",q:"What does 'hacer transbordo' mean?",opts:["To miss the train","To buy a ticket","To transfer between vehicles","To drive a car"],ans:"To transfer between vehicles",hint:"You do this when your route requires changing from one metro line to another."}
  ]}
]};
